using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResponse _evaluationMetrics;
    private readonly string[] _categoryLabels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build the pipeline: combine text features, normalize priority, train classifier
        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.NormalizeMinMax("PriorityNormalized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", "PriorityNormalized"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Extract ordered category labels from the key-value mapping
        var labelColumn = dataView.Schema[nameof(TicketData.Category)];
        var keyMap = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Fit(dataView);
        var keyCol = keyMap.Transform(dataView).Schema["Label"];
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        keyCol.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        // Evaluate with cross-validation on the full dataset
        _evaluationMetrics = Evaluate(dataView, pipeline);

        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    private EvaluationResponse Evaluate(IDataView data, IEstimator<ITransformer> pipeline)
    {
        // Use cross-validation to get meaningful metrics from the small dataset
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        var best = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var metrics = best.Metrics;

        var perCategory = new List<CategoryMetric>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            string label = i < _categoryLabels.Length ? _categoryLabels[i] : $"Class{i}";
            var cm = metrics.ConfusionMatrix;
            var counts = cm.Counts;

            double tp = counts[i][i];
            double colSum = 0;
            double rowSum = 0;
            for (int j = 0; j < counts.Count; j++)
            {
                colSum += counts[j][i];
                rowSum += counts[i][j];
            }

            perCategory.Add(new CategoryMetric
            {
                Category = label,
                Precision = colSum > 0 ? tp / colSum : 0,
                Recall = rowSum > 0 ? tp / rowSum : 0
            });
        }

        int sampleCount = (int)data.GetColumn<string>(nameof(TicketData.Category)).Count();

        return new EvaluationResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            TrainingSampleCount = sampleCount,
            PerCategoryMetrics = perCategory
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < _categoryLabels.Length; i++)
        {
            probabilities[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        };
    }

    public EvaluationResponse GetEvaluationMetrics() => _evaluationMetrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predict the category of a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    /// <summary>
    /// Return model evaluation metrics computed at startup.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(_classifier.GetEvaluationMetrics());
    }
}

